'use client'

import { useEffect, useState } from 'react'
import { Check, Loader2, RefreshCw, X, MessageSquare } from 'lucide-react'
import { toast } from 'sonner'
import { formatDistanceToNow } from 'date-fns'

interface PendingItem {
  id: string
  platform: string
  format: string
  title: string | null
  body: string
  agentReasoning: string | null
  confidence: number | null
  createdAt: string
}

export function ApprovalsPanel() {
  const [items, setItems] = useState<PendingItem[]>([])
  const [selectedId, setSelectedId] = useState<string | null>(null)
  const [feedback, setFeedback] = useState('')
  const [isLoading, setIsLoading] = useState(true)
  const [isActing, setIsActing] = useState(false)

  const selected = items.find((i) => i.id === selectedId) ?? items[0] ?? null

  async function load() {
    setIsLoading(true)
    try {
      const res = await fetch('/api/content/pending')
      if (res.ok) {
        const data = await res.json()
        const list = data.items || []
        setItems(list)
        if (!selectedId && list.length > 0) setSelectedId(list[0].id)
      }
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    load()
  }, [])

  async function approve(id: string) {
    setIsActing(true)
    try {
      const res = await fetch(`/api/content/${id}/approve`, { method: 'POST' })
      if (!res.ok) throw new Error('Approve failed')
      toast.success('Content approved')
      await load()
    } catch {
      toast.error('Failed to approve')
    } finally {
      setIsActing(false)
    }
  }

  async function reject(id: string) {
    setIsActing(true)
    try {
      const res = await fetch(`/api/content/${id}/reject`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ feedback: feedback || 'Rejected by reviewer' }),
      })
      if (!res.ok) throw new Error('Reject failed')
      toast.success('Content rejected')
      setFeedback('')
      await load()
    } catch {
      toast.error('Failed to reject')
    } finally {
      setIsActing(false)
    }
  }

  async function regenerate(id: string) {
    if (!feedback.trim()) {
      toast.error('Add feedback to guide regeneration')
      return
    }
    setIsActing(true)
    try {
      const res = await fetch(`/api/content/${id}/regenerate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ feedback }),
      })
      if (!res.ok) throw new Error('Regenerate failed')
      toast.success('Content regenerated — review the updated draft')
      setFeedback('')
      await load()
    } catch {
      toast.error('Failed to regenerate')
    } finally {
      setIsActing(false)
    }
  }

  if (isLoading) {
    return <div className="card p-12 text-center text-[#71717a]">Loading approvals...</div>
  }

  if (items.length === 0) {
    return (
      <div className="card p-12 text-center">
        <div className="text-lg font-medium mb-2">No pending approvals</div>
        <p className="text-sm text-[#71717a]">
          Run a planning cycle from the dashboard to generate content proposals.
        </p>
      </div>
    )
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-[280px_1fr] gap-6">
      <div className="space-y-2">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs uppercase tracking-widest text-[#71717a]">
            {items.length} pending
          </span>
          <button onClick={load} className="btn btn-ghost h-8 px-2 text-xs">
            <RefreshCw className="w-3.5 h-3.5" />
          </button>
        </div>
        {items.map((item) => (
          <button
            key={item.id}
            onClick={() => setSelectedId(item.id)}
            className={`w-full text-left card p-4 transition-colors ${
              selected?.id === item.id ? 'border-blue-500/50 bg-[#111113]' : 'hover:border-[#3f3f46]'
            }`}
          >
            <div className="flex gap-2 mb-1">
              <span className="text-[10px] px-2 py-0.5 rounded-full bg-[#27272a]">{item.platform}</span>
              <span className="text-[10px] px-2 py-0.5 rounded-full bg-[#27272a]">{item.format}</span>
            </div>
            <div className="text-sm font-medium line-clamp-2">
              {item.title || item.body.slice(0, 80)}
            </div>
            <div className="text-[10px] text-[#52525b] mt-1">
              {formatDistanceToNow(new Date(item.createdAt), { addSuffix: true })}
            </div>
          </button>
        ))}
      </div>

      {selected && (
        <div className="card p-6 space-y-6">
          <div className="flex flex-wrap gap-2">
            <span className="px-2.5 py-0.5 rounded-full bg-amber-500/10 text-amber-400 text-[10px] font-medium">
              PENDING APPROVAL
            </span>
            {selected.confidence != null && (
              <span className="text-[10px] text-[#71717a]">
                Confidence: {Math.round(selected.confidence * 100)}%
              </span>
            )}
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
            <div>
              <h3 className="text-xs uppercase tracking-widest text-[#71717a] mb-3">Draft content</h3>
              {selected.title && (
                <div className="font-semibold text-lg mb-3">{selected.title}</div>
              )}
              <pre className="whitespace-pre-wrap text-sm text-[#e4e4e7] leading-relaxed font-sans">
                {selected.body}
              </pre>
            </div>
            <div>
              <h3 className="text-xs uppercase tracking-widest text-[#71717a] mb-3">Agent reasoning</h3>
              <div className="p-4 rounded-xl bg-blue-500/5 border border-blue-500/20 text-sm text-[#a1a1aa] leading-relaxed">
                {selected.agentReasoning || 'No reasoning provided.'}
              </div>
            </div>
          </div>

          <div>
            <label className="block text-xs uppercase tracking-widest text-[#71717a] mb-2">
              Feedback (for reject or regenerate)
            </label>
            <textarea
              value={feedback}
              onChange={(e) => setFeedback(e.target.value)}
              placeholder="e.g. Make the hook stronger, shorten for LinkedIn, add a clearer CTA..."
              className="input w-full min-h-[80px] resize-y"
            />
          </div>

          <div className="flex flex-wrap gap-3 pt-2 border-t border-[#27272a]">
            <button
              onClick={() => approve(selected.id)}
              disabled={isActing}
              className="btn btn-primary h-10"
            >
              {isActing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4" />}
              Approve
            </button>
            <button
              onClick={() => regenerate(selected.id)}
              disabled={isActing}
              className="btn btn-secondary h-10"
            >
              <MessageSquare className="w-4 h-4" />
              Regenerate
            </button>
            <button
              onClick={() => reject(selected.id)}
              disabled={isActing}
              className="btn btn-ghost h-10 text-red-400 hover:text-red-300"
            >
              <X className="w-4 h-4" />
              Reject
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { RefreshCw, ExternalLink } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'

export interface ContentItemRow {
  id: string
  platform: string
  format: string
  title: string | null
  body: string
  status: string
  agentReasoning: string | null
  confidence: number | null
  createdAt: string
}

interface ContentListProps {
  title: string
  description: string
  formats: string[]
  emptyTitle: string
  emptyDescription: string
  reviewHref?: string
}

const statusColors: Record<string, string> = {
  PENDING_APPROVAL: 'text-amber-400 bg-amber-500/10',
  APPROVED: 'text-emerald-400 bg-emerald-500/10',
  PUBLISHED: 'text-blue-400 bg-blue-500/10',
  DRAFT: 'text-[#a1a1aa] bg-[#27272a]',
  REJECTED: 'text-red-400 bg-red-500/10',
}

export function ContentList({
  title,
  description,
  formats,
  emptyTitle,
  emptyDescription,
  reviewHref = '/content-studio/approvals',
}: ContentListProps) {
  const [items, setItems] = useState<ContentItemRow[]>([])
  const [isLoading, setIsLoading] = useState(true)

  async function load() {
    setIsLoading(true)
    try {
      const params = new URLSearchParams({ limit: '50' })
      formats.forEach((f) => params.append('format', f))
      const res = await fetch(`/api/content?${params}`)
      if (res.ok) {
        const data = await res.json()
        setItems(data.items || [])
      }
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    load()
  }, [formats.join(',')])

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h2 className="text-xl font-semibold tracking-tight">{title}</h2>
          <p className="text-sm text-[#71717a] mt-0.5">{description}</p>
        </div>
        <button onClick={load} className="btn btn-ghost h-9 px-3 text-xs border border-[#27272a]">
          <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {isLoading ? (
        <div className="card p-12 text-center text-[#71717a]">Loading content...</div>
      ) : items.length === 0 ? (
        <div className="card p-12 text-center">
          <div className="text-lg font-medium mb-2">{emptyTitle}</div>
          <p className="text-sm text-[#71717a] max-w-md mx-auto">{emptyDescription}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {items.map((item) => {
            const statusClass = statusColors[item.status] || statusColors.DRAFT
            return (
              <div key={item.id} className="card p-5 hover:border-[#3f3f46] transition-colors">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex-1 min-w-0">
                    <div className="flex flex-wrap items-center gap-2 mb-2">
                      <span className="px-2.5 py-0.5 rounded-full bg-[#27272a] text-[10px] font-medium">
                        {item.platform}
                      </span>
                      <span className="px-2.5 py-0.5 rounded-full bg-[#27272a] text-[10px] font-medium">
                        {item.format.replace('_', ' ')}
                      </span>
                      <span className={`px-2.5 py-0.5 rounded-full text-[10px] font-medium ${statusClass}`}>
                        {item.status.replace(/_/g, ' ')}
                      </span>
                      <span className="text-[10px] text-[#52525b]">
                        {formatDistanceToNow(new Date(item.createdAt), { addSuffix: true })}
                      </span>
                    </div>

                    {item.title && (
                      <div className="font-medium text-[15px] mb-1">{item.title}</div>
                    )}

                    <div className="text-sm text-[#a1a1aa] line-clamp-3 whitespace-pre-wrap">
                      {item.body}
                    </div>

                    {item.agentReasoning && (
                      <div className="text-xs text-[#71717a] mt-2 line-clamp-2">
                        <span className="text-[#a1a1aa] font-medium">Agent: </span>
                        {item.agentReasoning}
                      </div>
                    )}
                  </div>

                  {item.status === 'PENDING_APPROVAL' && (
                    <Link href={reviewHref} className="btn btn-secondary h-8 px-3 text-xs shrink-0">
                      <ExternalLink className="w-3 h-3" />
                      Review
                    </Link>
                  )}
                </div>
              </div>
            )
          })}
        </div>
      )}
    </div>
  )
}

'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { useState } from 'react'
import {
  LayoutDashboard,
  Building2,
  Clapperboard,
  Settings,
  ChevronDown,
  FileText,
  CheckCircle,
  Clock,
  Calendar,
  PauseCircle,
  Sparkles,
  FolderOpen,
} from 'lucide-react'
const contentStudioItems = [
  { href: '/content-studio/generate', label: 'Generate & Copy', icon: Sparkles },
  { href: '/content-studio/packages', label: 'Saved Packages', icon: FolderOpen },
  { href: '/content-studio/approvals', label: 'Agent Approvals', icon: CheckCircle },
  { href: '/content-studio/posts', label: 'Agent Posts', icon: FileText },
  { href: '/content-studio/activity', label: 'Activity', icon: Clock },
  { href: '/content-studio/calendar', label: 'Calendar', icon: Calendar },
]

const mainNav = [
  { href: '/', label: 'Dashboard', icon: LayoutDashboard },
  { href: '/businesses', label: 'Businesses', icon: Building2 },
]

function isContentStudioPath(pathname: string) {
  return pathname.startsWith('/content-studio')
}

export function AppSidebar() {
  const pathname = usePathname()
  const [studioOpen, setStudioOpen] = useState(isContentStudioPath(pathname))

  return (
    <aside className="app-sidebar w-[260px] shrink-0 border-r border-[#27272a] bg-[#09090b]/95 backdrop-blur flex flex-col sticky top-0 h-screen">
      {/* Brand */}
      <div className="px-5 py-5 border-b border-[#27272a]">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-600/20">
            <span className="font-bold text-sm tracking-[-0.5px]">TM</span>
          </div>
          <div>
            <div className="font-semibold tracking-[-0.3px] text-[15px] leading-none">TekMarketing</div>
            <div className="text-[9px] text-[#52525b] mt-0.5 tracking-widest">CONTENT STUDIO</div>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 overflow-y-auto px-3 py-4 space-y-1">
        {mainNav.map((item) => {
          const Icon = item.icon
          const isActive = pathname === item.href
          return (
            <Link
              key={item.href}
              href={item.href}
              className={`sidebar-link ${isActive ? 'active' : ''}`}
            >
              <Icon className="w-4 h-4 shrink-0" />
              <span>{item.label}</span>
            </Link>
          )
        })}

        {/* Content Studio section */}
        <div className="pt-2">
          <button
            onClick={() => setStudioOpen((o) => !o)}
            className={`sidebar-link w-full ${isContentStudioPath(pathname) ? 'active' : ''}`}
          >
            <Clapperboard className="w-4 h-4 shrink-0" />
            <span className="flex-1 text-left">Content Studio</span>
            <ChevronDown
              className={`w-4 h-4 shrink-0 transition-transform ${studioOpen ? 'rotate-180' : ''}`}
            />
          </button>

          {studioOpen && (
            <div className="mt-1 ml-3 pl-3 border-l border-[#27272a] space-y-0.5">
              {contentStudioItems.map((item) => {
                const Icon = item.icon
                const isActive = pathname === item.href
                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`sidebar-sublink ${isActive ? 'active' : ''}`}
                  >
                    <Icon className="w-3.5 h-3.5 shrink-0" />
                    <span>{item.label}</span>
                  </Link>
                )
              })}
            </div>
          )}
        </div>

        <div className="pt-2">
          <Link
            href="/settings"
            className={`sidebar-link ${pathname === '/settings' ? 'active' : ''}`}
          >
            <Settings className="w-4 h-4 shrink-0" />
            <span>Settings</span>
          </Link>
        </div>
      </nav>

      {/* Footer status */}
      <div className="px-4 py-4 border-t border-[#27272a] space-y-3">
        <div className="flex items-center gap-2 px-3 py-2 rounded-xl bg-[#111113] border border-[#27272a]">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shrink-0" />
          <span className="text-[11px] text-[#a1a1aa]">Agent • Daily 07:00 UTC</span>
        </div>
        <button
          onClick={() => alert('Pause scheduled runs coming soon. Manual cycles still work.')}
          className="w-full flex items-center justify-center gap-1.5 px-3 py-2 rounded-xl bg-[#111113] border border-[#27272a] text-[11px] text-[#a1a1aa] hover:text-[#f4f4f5] hover:border-[#3f3f46] transition-colors"
        >
          <PauseCircle className="w-3.5 h-3.5" />
          Pause Agent
        </button>
      </div>
    </aside>
  )
}

'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { 
  LayoutDashboard, 
  Calendar, 
  CheckCircle, 
  Users, 
  BarChart3,
  PauseCircle,
  Clock
} from 'lucide-react'

const navItems = [
  { href: '/', label: 'Dashboard', icon: LayoutDashboard },
  { href: '/approvals', label: 'Approvals', icon: CheckCircle },
  { href: '/activity', label: 'Activity', icon: Clock },
  { href: '/brand', label: 'Brand & Strategy', icon: Users },
  { href: '/analytics', label: 'Analytics', icon: BarChart3 },
]

export function DashboardNav() {
  const pathname = usePathname()

  return (
    <div className="flex items-center gap-1 text-sm">
      {navItems.map((item) => {
        const Icon = item.icon
        const isActive = pathname === item.href
        return (
          <Link
            key={item.href}
            href={item.href}
            className={`nav-link flex items-center gap-2 ${isActive ? 'active' : ''}`}
          >
            <Icon className="w-4 h-4" />
            {item.label}
          </Link>
        )
      })}
    </div>
  )
}

export function AgentStatusBar() {
  return (
    <div className="flex items-center gap-3 text-xs">
      <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-[#111113] border border-[#27272a]">
        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
        <span className="text-[#a1a1aa]">Scheduled • Daily 07:00 UTC</span>
      </div>
      <button 
        onClick={() => alert("Pause scheduled runs coming soon. Manual cycles still work.")}
        className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-[#111113] border border-[#27272a] text-[#a1a1aa] hover:text-[#f4f4f5] hover:border-[#3f3f46] transition-colors"
      >
        <PauseCircle className="w-3.5 h-3.5" />
        <span>Pause Agent</span>
      </button>
    </div>
  )
}

interface PageHeaderProps {
  eyebrow?: string
  title: string
  description?: string
  action?: React.ReactNode
}

export function PageHeader({ eyebrow, title, description, action }: PageHeaderProps) {
  return (
    <div className="flex items-start justify-between gap-6 mb-8">
      <div>
        {eyebrow && (
          <div className="uppercase tracking-[2px] text-[10px] text-[#71717a] mb-2">{eyebrow}</div>
        )}
        <h1 className="text-3xl font-semibold tracking-[-1px]">{title}</h1>
        {description && <p className="text-[#71717a] mt-1.5 text-sm max-w-2xl">{description}</p>}
      </div>
      {action && <div className="shrink-0">{action}</div>}
    </div>
  )
}

'use client'

import { useState } from 'react'
import { Check, Copy } from 'lucide-react'
import { toast } from 'sonner'

interface CopyButtonProps {
  text: string
  label?: string
  variant?: 'primary' | 'secondary' | 'ghost'
  iconOnly?: boolean
  className?: string
}

export function CopyButton({
  text,
  label = 'Copy',
  variant = 'secondary',
  iconOnly = false,
  className = '',
}: CopyButtonProps) {
  const [copied, setCopied] = useState(false)

  async function handleCopy() {
    try {
      await navigator.clipboard.writeText(text)
      setCopied(true)
      toast.success('Copied to clipboard')
      setTimeout(() => setCopied(false), 2000)
    } catch {
      toast.error('Failed to copy')
    }
  }

  const variantClass =
    variant === 'primary'
      ? 'btn-primary'
      : variant === 'ghost'
        ? 'btn-ghost'
        : 'btn-secondary'

  return (
    <button
      type="button"
      onClick={handleCopy}
      className={`btn h-8 px-3 text-xs ${variantClass} ${className}`}
      title={label}
    >
      {copied ? <Check className="w-3.5 h-3.5" /> : <Copy className="w-3.5 h-3.5" />}
      {!iconOnly && (copied ? 'Copied' : label)}
    </button>
  )
}

'use client'

import { Download } from 'lucide-react'
import { toast } from 'sonner'

interface DownloadTextButtonProps {
  text: string
  filename: string
  label?: string
  variant?: 'primary' | 'secondary' | 'ghost'
}

export function DownloadTextButton({
  text,
  filename,
  label = 'Download',
  variant = 'secondary',
}: DownloadTextButtonProps) {
  function handleDownload() {
    try {
      const blob = new Blob([text], { type: 'text/plain;charset=utf-8' })
      const url = URL.createObjectURL(blob)
      const anchor = document.createElement('a')
      anchor.href = url
      anchor.download = filename.endsWith('.txt') ? filename : `${filename}.txt`
      anchor.click()
      URL.revokeObjectURL(url)
      toast.success('Download started')
    } catch {
      toast.error('Failed to download')
    }
  }

  const variantClass =
    variant === 'primary' ? 'btn-primary' : variant === 'ghost' ? 'btn-ghost' : 'btn-secondary'

  return (
    <button type="button" onClick={handleDownload} className={`btn h-8 px-3 text-xs ${variantClass}`}>
      <Download className="w-3.5 h-3.5" />
      {label}
    </button>
  )
}
